class Solution:
    def numDupDigitsAtMostN(self, n):
        s = str(n)
        L = len(s)
        from functools import lru_cache
        # count integers in [0, n] whose digits are all distinct, via digit DP
        # state: position, bitmask of used digits, tight, started
        @lru_cache(maxsize=None)
        def dp(pos, mask, tight, started):
            if pos == L:
                return 1
            total = 0
            hi = int(s[pos]) if tight else 9
            for d in range(0, hi + 1):
                ns = started or d > 0
                if ns and (mask >> d) & 1:
                    continue
                nmask = mask | (1 << d) if ns else mask
                total += dp(pos + 1, nmask, tight and d == hi, ns)
            return total
        distinct_including_zero = dp(0, 0, True, False)
        distinct_positive = distinct_including_zero - 1
        return n - distinct_positive

