class Solution:
    def numDupDigitsAtMostN(self, n):
        digits = [int(c) for c in str(n)]
        L = len(digits)
        def perm(m, k):
            r = 1
            for i in range(k):
                r *= (m - i)
            return r
        distinct = 0
        for length in range(1, L):
            distinct += 9 * perm(9, length - 1)
        used = set()
        for i, d in enumerate(digits):
            start = 1 if i == 0 else 0
            for x in range(start, d):
                if x in used:
                    continue
                distinct += perm(9 - i, L - i - 1)
            if d in used:
                break
            used.add(d)
        else:
            distinct += 1
        return n - distinct

