var numDupDigitsAtMostN = function(n) {
    const digits = String(n).split('').map(Number);
    const L = digits.length;
    const perm = (m, k) => {
        let r = 1;
        for (let i = 0; i < k; i++) r *= (m - i);
        return r;
    };
    let distinct = 0;
    for (let length = 1; length < L; length++) {
        distinct += 9 * perm(9, length - 1);
    }
    const used = new Set();
    let broke = false;
    for (let i = 0; i < L; i++) {
        const d = digits[i];
        const start = i === 0 ? 1 : 0;
        for (let x = start; x < d; x++) {
            if (used.has(x)) continue;
            distinct += perm(9 - i, L - i - 1);
        }
        if (used.has(d)) { broke = true; break; }
        used.add(d);
    }
    if (!broke) distinct += 1;
    return n - distinct;
};
